import React from 'react';

type BadgeVariant = 'success' | 'warning' | 'error' | 'info' | 'neutral';

const colors: Record<BadgeVariant, { bg: string; text: string }> = {
  success: { bg: 'var(--color-success-light)', text: 'var(--color-success)' },
  warning: { bg: 'var(--color-warning-light)', text: 'var(--color-warning)' },
  error:   { bg: 'var(--color-error-light)', text: 'var(--color-error)' },
  info:    { bg: 'var(--color-info-light)', text: 'var(--color-info)' },
  neutral: { bg: 'var(--color-neutral-100)', text: 'var(--color-neutral-700)' },
};

interface BadgeProps {
  variant?: BadgeVariant;
  children: React.ReactNode;
}

export const Badge: React.FC<BadgeProps> = ({ variant = 'neutral', children }) => {
  const c = colors[variant];
  return (
    <span style={{
      display: 'inline-flex', alignItems: 'center', padding: '1px var(--spacing-2)',
      fontSize: 'var(--font-size-xs)', fontWeight: 600, borderRadius: '9999px',
      backgroundColor: c.bg, color: c.text, lineHeight: 1.5,
    }}>
      {children}
    </span>
  );
};

// Tabs component
interface TabsProps {
  tabs: { key: string; label: string }[];
  activeKey: string;
  onChange: (key: string) => void;
}

export const Tabs: React.FC<TabsProps> = ({ tabs, activeKey, onChange }) => (
  <div style={{ display: 'flex', borderBottom: '2px solid var(--color-neutral-200)', gap: 0 }}>
    {tabs.map(tab => (
      <button
        key={tab.key}
        onClick={() => onChange(tab.key)}
        style={{
          padding: 'var(--spacing-2) var(--spacing-4)', background: 'none', border: 'none',
          borderBottom: activeKey === tab.key ? '2px solid var(--color-primary-500)' : '2px solid transparent',
          marginBottom: -2, color: activeKey === tab.key ? 'var(--color-primary-600)' : 'var(--color-neutral-500)',
          fontWeight: activeKey === tab.key ? 600 : 400, cursor: 'pointer', fontSize: 'var(--font-size-sm)',
        }}
      >
        {tab.label}
      </button>
    ))}
  </div>
);
