import React from 'react';

interface CardProps {
  title?: string;
  subtitle?: string;
  children: React.ReactNode;
  footer?: React.ReactNode;
  onClick?: () => void;
  className?: string;
  style?: React.CSSProperties;
}

export const Card: React.FC<CardProps> = ({ title, subtitle, children, footer, onClick, style }) => (
  <div
    onClick={onClick}
    style={{
      background: '#fff', borderRadius: 'var(--radius-lg)', border: '1px solid var(--color-neutral-200)',
      boxShadow: 'var(--shadow-sm)', cursor: onClick ? 'pointer' : undefined,
      transition: 'box-shadow var(--transition-fast)', ...style,
    }}
  >
    {(title || subtitle) && (
      <div style={{ padding: 'var(--spacing-4)', borderBottom: title ? '1px solid var(--color-neutral-100)' : undefined }}>
        {title && <h3 style={{ margin: 0, fontSize: 'var(--font-size-lg)', fontWeight: 600 }}>{title}</h3>}
        {subtitle && <p style={{ margin: 'var(--spacing-1) 0 0', color: 'var(--color-neutral-500)', fontSize: 'var(--font-size-sm)' }}>{subtitle}</p>}
      </div>
    )}
    <div style={{ padding: 'var(--spacing-4)' }}>{children}</div>
    {footer && <div style={{ padding: 'var(--spacing-4)', borderTop: '1px solid var(--color-neutral-100)' }}>{footer}</div>}
  </div>
);
