import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  loading?: boolean;
}

const variantStyles: Record<string, React.CSSProperties> = {
  primary: {
    backgroundColor: 'var(--color-primary-600)',
    color: '#fff',
    border: 'none',
  },
  secondary: {
    backgroundColor: 'var(--color-neutral-200)',
    color: 'var(--color-neutral-800)',
    border: '1px solid var(--color-neutral-300)',
  },
  danger: {
    backgroundColor: 'var(--color-error)',
    color: '#fff',
    border: 'none',
  },
  ghost: {
    backgroundColor: 'transparent',
    color: 'var(--color-primary-600)',
    border: 'none',
  },
};

const sizeStyles: Record<string, React.CSSProperties> = {
  sm: { padding: 'var(--spacing-1) var(--spacing-3)', fontSize: 'var(--font-size-sm)' },
  md: { padding: 'var(--spacing-2) var(--spacing-4)', fontSize: 'var(--font-size-base)' },
  lg: { padding: 'var(--spacing-3) var(--spacing-6)', fontSize: 'var(--font-size-lg)' },
};

export const Button: React.FC<ButtonProps> = ({
  variant = 'primary',
  size = 'md',
  loading = false,
  disabled,
  children,
  style,
  ...props
}) => {
  const baseStyle: React.CSSProperties = {
    display: 'inline-flex',
    alignItems: 'center',
    justifyContent: 'center',
    gap: 'var(--spacing-2)',
    borderRadius: 'var(--radius-md)',
    fontWeight: 500,
    cursor: disabled || loading ? 'not-allowed' : 'pointer',
    opacity: disabled || loading ? 0.6 : 1,
    transition: 'var(--transition-fast)',
    ...variantStyles[variant],
    ...sizeStyles[size],
    ...style,
  };

  return (
    <button style={baseStyle} disabled={disabled || loading} {...props}>
      {loading && <Spinner size={14} />}
      {children}
    </button>
  );
};

const Spinner: React.FC<{ size?: number }> = ({ size = 16 }) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 24 24"
    style={{ animation: 'spin 0.75s linear infinite' }}
  >
    <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    <circle
      cx="12" cy="12" r="10"
      fill="none"
      stroke="currentColor"
      strokeWidth="3"
      strokeDasharray="32"
      strokeLinecap="round"
      opacity={0.3}
    />
    <circle
      cx="12" cy="12" r="10"
      fill="none"
      stroke="currentColor"
      strokeWidth="3"
      strokeDasharray="32"
      strokeDashoffset="24"
      strokeLinecap="round"
    />
  </svg>
);
